const mixColors = (colors) => {
  if (colors.length === 0) return '#1e293b';
  if (colors.length === 1) return colors[0];
  let r = 0, g = 0, b = 0;
  colors.forEach(hex => {
    const result = /^#?([a-f\d]{2})([a-f\d]{2})([a-f\d]{2})$/i.exec(hex);
    if(result) { r += parseInt(result[1], 16); g += parseInt(result[2], 16); b += parseInt(result[3], 16); }
  });
  const avg = (val) => Math.round(val / colors.length).toString(16).padStart(2, '0');
  return `#${avg(r)}${avg(g)}${avg(b)}`;
};

const initialStopState = { name: '', venue: '', phase: '1', color: '#3b82f6', startDate: new Date().toISOString().split('T')[0] };

function App() {
  const [lang, setLang] = useState('zh');
  const t = translations[lang];
  const [currentProject, setCurrentProject] = useState('默认规划图');
  const [projectMetadata, setProjectMetadata] = useState({});
  const [globalPassConfig, setGlobalPassConfig] = useState({ admin: '', view: '', write: '' });
  const [projects, setProjects] = useState(['默认规划图']);
  const [stops, setStops] = useState([]);
  const [isEditing, setIsEditing] = useState(false);
  const [editingId, setEditingId] = useState(null);
  const [showSettings, setShowSettings] = useState(false);
  const [newStop, setNewStop] = useState(initialStopState);
  const [userRole, setUserRole] = useState(null); 
  const [speedMultiplier, setSpeedMultiplier] = useState(10.0);

  const mapRef = useRef(null);
  const clusterGroupRef = useRef(null);
  const mapContainerRef = useRef(null);
  const layersRef = useRef({ paths: [], arrows: [] });

  useEffect(() => {
    onValue(ref(db, 'projects'), (snap) => {
      const data = snap.val();
      if (data) { setProjects(Object.keys(data).filter(k => !k.startsWith('-') && typeof data[k] === 'object')); setProjectMetadata(data); }
    });
    onValue(ref(db, 'systemConfig/passwords'), (snap) => {
      if (snap.val()) setGlobalPassConfig(snap.val());
    });
  }, []);

  useEffect(() => {
    return onValue(ref(db, `projects/${currentProject}/stops`), (snap) => {
      const data = snap.val();
      setStops(data ? Object.entries(data).map(([id, val]) => ({ id, ...val })).sort((a,b) => a.order - b.order) : []);
    });
  }, [currentProject]);

  useEffect(() => {
    if (!mapContainerRef.current || mapRef.current || !window.L) return;
    mapRef.current = window.L.map(mapContainerRef.current, { zoomControl: false, attributionControl: false }).setView([34.3416, 108.9398], 4);
    window.L.tileLayer('https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png').addTo(mapRef.current);
    clusterGroupRef.current = window.L.markerClusterGroup({ 
      showCoverageOnHover: false,
      iconCreateFunction: (cluster) => {
        const markers = cluster.getAllChildMarkers();
        const blendedColor = mixColors(markers.map(m => m.options.phaseColor));
        return window.L.divIcon({
          html: `<div style="background:${blendedColor}; color:white; border-radius:50%; width:44px; height:44px; display:flex; align-items:center; justify-content:center; border:3px solid white; font-weight:900; box-shadow: 0 4px 15px rgba(0,0,0,0.3); font-size:14px;">${markers.length}</div>`,
          iconSize: [44, 44]
        });
      }
    }).addTo(mapRef.current);
  }, []);

  useEffect(() => {
    if (!mapRef.current || !clusterGroupRef.current || !userRole) return;
    clusterGroupRef.current.clearLayers();
    layersRef.current.paths.forEach(p => p.remove());
    layersRef.current.arrows.forEach(a => a.remove());
    layersRef.current = { paths: [], arrows: [] };
    const animationIds = [];

    Object.values(groupedStops).forEach((group) => {
      const pathCoords = group.stops.map(s => [s.lat, s.lng]);
      const markers = group.stops.map(stop => {
        const icon = window.L.divIcon({
          className: 'custom-pin',
          html: `<div style="display: flex; align-items: center; gap: 10px;">
                    <div style="position: relative; width: 34px; height: 34px;">
                        <svg width="34" height="34" viewBox="0 0 24 24" fill="${stop.color}" stroke="white" stroke-width="2"><path d="M21 10c0 7-9 13-9 13s-9-6-9-13a9 9 0 0 1 18 0z"></path></svg>
                        <span style="position: absolute; top: 45%; left: 50%; transform: translate(-50%, -50%); color: white; font-size: 10px; font-weight: 900;">${stop.phaseIndex}</span>
                    </div>
                    <div style="background: white; padding: 4px 10px; border-radius: 8px; border: 1.5px solid ${stop.color}; box-shadow: 0 4px 6px rgba(0,0,0,0.1); display: flex; flex-direction: column;">
                        <span style="font-size: 8px; font-weight: 900; color: ${stop.color}; uppercase">${stop.startDate}</span>
                        <span style="font-size: 11px; font-weight: 700; color: #0f172a; white-space: nowrap;">${stop.venue || stop.name}</span>
                    </div>
                 </div>`,
          iconAnchor: [17, 34]
        });
        const m = window.L.marker([stop.lat, stop.lng], { icon, phaseColor: stop.color });
        clusterGroupRef.current.addLayer(m);
        return m;
      });

      if (pathCoords.length > 1) {
        const poly = window.L.polyline(pathCoords, { color: group.color, weight: 4, dashArray: '10, 15', className: 'marching-ants' }).addTo(mapRef.current);
        layersRef.current.paths.push(poly);
        const arrowMarker = window.L.marker(pathCoords[0], { 
          icon: window.L.divIcon({ className: 'custom-pin', html: `<div class="arrow-wrapper" style="color:${group.color}; opacity:1;"><svg width="28" height="28" viewBox="0 0 24 24"><path d="M12 2L22 22L12 18L2 22L12 2Z" fill="currentColor" stroke="white" stroke-width="1"/></svg></div>`, iconSize: [28,28], iconAnchor: [14,14] }) 
        }).addTo(mapRef.current);
        layersRef.current.arrows.push(arrowMarker);

        let totalD = 0; const segs = [];
        for(let i=0; i<pathCoords.length-1; i++) {
          const d = mapRef.current.distance(pathCoords[i], pathCoords[i+1]);
          segs.push({ s: pathCoords[i], e: pathCoords[i+1], d, c: totalD, sm: markers[i], em: markers[i+1] });
          totalD += d;
        }

        let start = null;
        const anim = (t) => {
          if(!start) start = t;
          let traveled = ((t - start) * (0.06 * speedMultiplier)) % (totalD || 1);
          const seg = segs.find((s, idx) => traveled >= s.c && (idx === segs.length-1 || traveled < segs[idx+1].c));
          if(seg) {
            const ang = Math.atan2(mapRef.current.latLngToContainerPoint(seg.e).y - mapRef.current.latLngToContainerPoint(seg.s).y, mapRef.current.latLngToContainerPoint(seg.e).x - mapRef.current.latLngToContainerPoint(seg.s).x) * (180 / Math.PI) + 90;
            arrowMarker.setLatLng([seg.s[0] + (seg.e[0] - seg.s[0]) * ((traveled - seg.c) / seg.d), seg.s[1] + (seg.e[1] - seg.s[1]) * ((traveled - seg.c) / seg.d)]);
            const el = arrowMarker.getElement();
            if(el) { const w = el.querySelector('.arrow-wrapper'); if(w) w.style.transform = `rotate(${ang}deg)`; }
          }
          animationIds.push(requestAnimationFrame(anim));
        };
        requestAnimationFrame(anim);
      }
    });
    return () => animationIds.forEach(id => cancelAnimationFrame(id));
  }, [stops, userRole, speedMultiplier]);

  const groupedStops = useMemo(() => {
    const groups = {};
    [...stops].sort((a, b) => a.order - b.order).forEach((stop) => {
      if (!groups[stop.phase]) groups[stop.phase] = { stops: [], color: stop.color };
      groups[stop.phase].stops.push({ ...stop, phaseIndex: groups[stop.phase].stops.length + 1 });
    });
    return groups;
  }, [stops]);

  const login = () => {
    const p = window.prompt(t.enterAccess);
    if (p === globalPassConfig.admin || (!globalPassConfig.admin && p === 'admin')) setUserRole('admin');
    else if (globalPassConfig.write && p === globalPassConfig.write) setUserRole('write');
    else if (globalPassConfig.view && p === globalPassConfig.view) setUserRole('view');
    else alert(t.wrongPass);
  };

  const handleUpdatePassword = async (type) => {
    const p = window.prompt(`${t.save} ${type} ${t.adminPass}`);
    if (p !== null) {
      await update(ref(db, 'systemConfig/passwords'), { [type]: p });
      alert(lang === 'zh' ? '密码已更新' : 'Password updated');
    }
  };

  // ROBUST EXCEL IMPORT
  const importExcel = (e) => {
    const file = e.target.files[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = async (evt) => {
      const bstr = evt.target.result;
      const wb = XLSX.read(bstr, { type: 'binary' });
      const wsname = wb.SheetNames[0];
      const ws = wb.Sheets[wsname];
      const data = XLSX.utils.sheet_to_json(ws);
      
      let importedCount = 0;
      for (const row of data) {
        // Handle variations in header naming
        const findVal = (keys) => {
           const key = Object.keys(row).find(k => keys.includes(k.trim().toLowerCase()));
           return key ? String(row[key]).trim() : '';
        };

        const name = findVal(['city', '城市', 'name']);
        const venue = findVal(['venue', '场馆', 'location']);
        const phase = findVal(['phase', '阶段', 'step']) || '1';
        const date = findVal(['date', '日期', 'time']);

        if (!name) continue;

        // Strict duplicate check
        const isDuplicate = stops.some(s => 
          s.name === name && 
          s.venue === venue && 
          String(s.phase) === String(phase) && 
          s.startDate === date
        );

        if (!isDuplicate) {
          try {
            const r = await fetch(`https://nominatim.openstreetmap.org/search?format=json&q=${encodeURIComponent(name + ' ' + venue)}`);
            const g = await r.json();
            if (g[0]) {
              await set(push(ref(db, `projects/${currentProject}/stops`)), {
                name, venue, phase, startDate: date,
                color: groupedStops[phase]?.color || '#3b82f6',
                lat: parseFloat(g[0].lat), lng: parseFloat(g[0].lon),
                order: stops.length + importedCount
              });
              importedCount++;
            }
          } catch (err) { console.error("Geocoding failed for", name); }
        }
      }
      alert(lang === 'zh' ? `成功导入 ${importedCount} 个站点` : `Successfully imported ${importedCount} stops`);
    };
    reader.readAsBinaryString(file);
    e.target.value = null; // Reset input
  };

  const exportExcel = () => {
    const data = stops.map(s => ({ Phase: s.phase, City: s.name, Venue: s.venue, Date: s.startDate }));
    const ws = XLSX.utils.json_to_sheet(data);
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, "Stops");
    XLSX.writeFile(wb, `${currentProject}_Route.xlsx`);
  };

  const exportImage = () => {
    htmlToImage.toPng(mapContainerRef.current, { quality: 1.0, backgroundColor: '#ffffff' }).then(dataUrl => {
      const link = document.createElement('a');
      link.download = `${currentProject}_Map.png`;
      link.href = dataUrl;
      link.click();
    });
  };

  const handleSaveStop = async () => {
    const r=await fetch(`https://nominatim.openstreetmap.org/search?format=json&q=${encodeURIComponent(newStop.name+' '+newStop.venue)}`);
    const g=await r.json();
    if(g[0]){
      const data = {...newStop, lat:parseFloat(g[0].lat), lng:parseFloat(g[0].lon), order: editingId ? newStop.order : stops.length};
      if (editingId) await set(ref(db, `projects/${currentProject}/stops/${editingId}`), data);
      else await set(push(ref(db, `projects/${currentProject}/stops`)), data);
      setIsEditing(false); setEditingId(null); setNewStop(initialStopState);
    }
  };

  const moveStop = async (index, direction) => {
    const newStops = [...stops];
    const target = index + direction;
    if (target < 0 || target >= newStops.length) return;
    [newStops[index], newStops[target]] = [newStops[target], newStops[index]];
    const updates = {};
    newStops.forEach((s, i) => { updates[`projects/${currentProject}/stops/${s.id}/order`] = i; });
    await update(ref(db), updates);
  };

  return (
    <div className="flex flex-col h-screen bg-slate-50 overflow-hidden font-sans text-slate-900 relative">
      <style>{`.custom-pin { background: none !important; border: none !important; } .marching-ants { animation: dash 1s linear infinite; } @keyframes dash { to { stroke-dashoffset: -20; } }`}</style>
      
      {!userRole && (
        <div className="absolute inset-0 z-[300] bg-slate-900 flex items-center justify-center p-10 animate-in fade-in duration-500">
          <div className="bg-white p-12 rounded-[60px] shadow-2xl flex flex-col items-center gap-8 max-w-sm w-full text-center border">
             <div className="bg-blue-600 p-6 rounded-full shadow-xl shadow-blue-200"><Shield size={48} className="text-white"/></div>
             <div><h1 className="text-3xl font-black uppercase tracking-tighter text-slate-800">RP.2026</h1><p className="text-slate-400 font-bold text-xs uppercase tracking-widest mt-2">{t.enterAccess}</p></div>
             <button onClick={login} className="w-full py-5 bg-blue-600 text-white rounded-3xl font-black uppercase tracking-widest shadow-lg hover:scale-105 transition-all">{t.save}</button>
          </div>
        </div>
      )}

      {showSettings && (
        <>
          <div className="absolute inset-0 bg-slate-900/10 backdrop-blur-sm z-[100]" onClick={() => setShowSettings(false)} />
          <div className="absolute right-0 top-0 bottom-0 w-80 bg-white shadow-2xl z-[110] border-l p-8 animate-in slide-in-from-right duration-300 flex flex-col">
            <div className="flex justify-between items-center mb-10"><h3 className="text-xl font-black flex items-center gap-2 text-slate-800"><Settings size={22}/> {t.settings}</h3><button onClick={()=>setShowSettings(false)} className="p-2 hover:bg-slate-100 rounded-full transition-colors"><X size={24}/></button></div>
            <div className="space-y-6 flex-1 overflow-y-auto pr-2">
                {userRole === 'admin' && (
                  <div className="p-4 bg-blue-50 rounded-2xl border border-blue-100 space-y-3">
                    <p className="text-[10px] font-black text-blue-400 uppercase tracking-widest flex items-center gap-2"><Key size={12}/> {t.security}</p>
                    <div className="space-y-2">
                        <button onClick={()=>handleUpdatePassword('admin')} className="w-full flex items-center justify-between p-3 bg-white border rounded-xl hover:bg-blue-50 transition-all shadow-sm"><span className="text-[10px] font-black uppercase text-slate-500">{t.adminPass}</span><Edit3 size={14} className="text-blue-500" /></button>
                        <button onClick={()=>handleUpdatePassword('write')} className="w-full flex items-center justify-between p-3 bg-white border rounded-xl hover:bg-blue-50 transition-all shadow-sm"><span className="text-[10px] font-black uppercase text-slate-500">{t.writePass}</span><Edit3 size={14} className="text-blue-500" /></button>
                        <button onClick={()=>handleUpdatePassword('view')} className="w-full flex items-center justify-between p-3 bg-white border rounded-xl hover:bg-blue-50 transition-all shadow-sm"><span className="text-[10px] font-black uppercase text-slate-500">{t.viewPass}</span><Edit3 size={14} className="text-blue-500" /></button>
                    </div>
                  </div>
                )}
                <div className="p-4 bg-slate-50 rounded-2xl border space-y-2">
                   <button onClick={exportExcel} className="w-full py-3 bg-white border rounded-xl font-black text-xs uppercase flex items-center justify-center gap-2 shadow-sm"><FileDown size={14}/>{t.exportEx}</button>
                   {userRole !== 'view' && (
                     <label className="w-full py-3 bg-white border rounded-xl font-black text-xs uppercase flex items-center justify-center gap-2 shadow-sm cursor-pointer hover:bg-slate-50">
                       <FileUp size={14}/>{t.importEx}
                       <input type="file" className="hidden" accept=".xlsx, .xls" onChange={importExcel} />
                     </label>
                   )}
                   <button onClick={exportImage} className="w-full py-3 bg-white border rounded-xl font-black text-xs uppercase flex items-center justify-center gap-2 shadow-sm"><ImageIcon size={14}/>{t.exportImg}</button>
                </div>
                <button onClick={() => { if(mapRef.current && stops.length > 0) mapRef.current.fitBounds(stops.map(s => [s.lat, s.lng]), {padding:[50,50]}); }} className="w-full py-4 bg-slate-900 text-white rounded-2xl font-black text-sm flex items-center justify-center gap-2 shadow-lg uppercase tracking-widest"><Maximize size={18} />{t.fit}</button>
                {userRole === 'admin' && <button onClick={()=>{const n=window.prompt(t.new); if(n){set(ref(db,`projects/${n}/created`),Date.now()); setCurrentProject(n); setShowSettings(false);}}} className="w-full py-4 bg-blue-600 text-white rounded-2xl font-black text-sm flex items-center justify-center gap-2 shadow-lg uppercase tracking-widest"><PlusCircle size={18} />{t.new}</button>}
                <button onClick={()=>window.location.reload()} className="w-full py-3 text-red-400 font-black text-xs uppercase border border-red-100 rounded-xl hover:bg-red-50 mt-4">{t.logout}</button>
            </div>
          </div>
        </>
      )}

      <header className="flex items-center justify-between px-10 py-5 bg-white border-b shadow-sm z-10">
        <div className="flex items-center gap-6">
          <h1 className="text-xl font-black text-blue-600 uppercase tracking-tighter">RP.2026</h1>
          {userRole === 'admin' && (
            <div className="flex flex-col border-l pl-6">
              <span className="text-[10px] font-bold text-slate-400 uppercase tracking-tighter">{t.select}</span>
              <select className="bg-transparent font-bold text-sm outline-none cursor-pointer" value={currentProject} onChange={(e)=>setCurrentProject(e.target.value)}>{projects.map(p => <option key={p} value={p}>{p}</option>)}</select>
            </div>
          )}
        </div>
        <div className="flex items-center gap-6">
          <div className="flex items-center gap-3 bg-slate-50 px-4 py-2 rounded-xl border">
             <Sliders size={16} className="text-slate-400" /><input type="range" min="1" max="100" step="1" value={speedMultiplier} onChange={(e)=>setSpeedMultiplier(parseFloat(e.target.value))} className="w-24 h-1.5 accent-blue-600 appearance-none bg-slate-200 rounded-full cursor-pointer" />
             <span className="text-[10px] font-black text-blue-600 w-6">{Math.round(speedMultiplier/10)}x</span>
          </div>
          <div className="flex items-center gap-2 border-l pl-6">
            {(userRole === 'admin' || userRole === 'write') && <button onClick={()=>{if(window.confirm(t.clear)) remove(ref(db,`projects/${currentProject}/stops`));}} className="p-2 text-orange-400 hover:bg-orange-50 rounded-lg transition-colors"><Trash2 size={20}/></button>}
            <button onClick={()=>setShowSettings(true)} className="p-2 text-slate-400 hover:bg-slate-50 rounded-lg transition-colors"><Settings size={20}/></button>
          </div>
          <div className="flex items-center gap-2 border-l pl-6">
            <Globe size={18} className="text-slate-400" /><select className="text-xs font-black outline-none bg-transparent" value={lang} onChange={(e)=>setLang(e.target.value)}><option value="zh">ZH</option><option value="en">EN</option></select>
          </div>
          {(userRole === 'admin' || userRole === 'write') && <button onClick={()=>{setIsEditing(true); setEditingId(null); setNewStop(initialStopState);}} className="px-6 py-2.5 bg-blue-600 text-white rounded-2xl font-black text-sm shadow-lg hover:scale-105 transition-all shadow-blue-100 uppercase tracking-widest">+ {t.addStop}</button>}
        </div>
      </header>

      <main className="flex flex-1 p-6 gap-6 overflow-hidden">
        <div className={`w-[420px] bg-white rounded-[40px] shadow-2xl border flex flex-col overflow-hidden z-20 transition-all ${userRole === 'view' ? 'hidden' : ''}`}>
          {isEditing ? (
            <div className="p-10 space-y-6 flex flex-col h-full">
              <div className="flex justify-between items-center"><h2 className="text-2xl font-black text-blue-600 tracking-tighter uppercase">{editingId ? t.edit : t.addStop}</h2><button onClick={()=>{setIsEditing(false); setEditingId(null);}} className="p-2 hover:bg-slate-100 rounded-full"><X size={20}/></button></div>
              <div className="space-y-4">
                  <input className="w-full p-4 bg-slate-50 rounded-2xl font-bold border focus:border-blue-500 uppercase transition-all" lang="zh" placeholder={t.city} value={newStop.name} onChange={e=>setNewStop({...newStop,name:e.target.value})} />
                  <input className="w-full p-4 bg-slate-50 rounded-2xl font-bold border focus:border-blue-500 transition-all" lang="zh" placeholder={t.venue} value={newStop.venue} onChange={e=>setNewStop({...newStop,venue:e.target.value})} />
                  <div className="grid grid-cols-2 gap-4">
                    <div><label className="text-[10px] font-bold text-slate-400 ml-2 mb-1 block uppercase">{t.phase}</label><select className="w-full p-4 bg-slate-50 rounded-2xl font-bold border" value={newStop.phase} onChange={e=>setNewStop({...newStop, phase:e.target.value})}>{[...Array(20)].map((_,i)=><option key={i+1} value={i+1}>{i+1}</option>)}</select></div>
                    <div><label className="text-[10px] font-bold text-slate-400 ml-2 mb-1 block uppercase">{t.color}</label><input type="color" className="w-full h-14 p-1 bg-slate-50 rounded-2xl border cursor-pointer" value={newStop.color} onChange={e=>setNewStop({...newStop,color:e.target.value})} /></div>
                  </div>
                  <input type="date" className="w-full p-4 bg-slate-50 rounded-2xl font-bold border" value={newStop.startDate} onChange={e=>setNewStop({...newStop, startDate: e.target.value})} />
              </div>
              <button onClick={handleSaveStop} className="mt-auto w-full py-5 bg-blue-600 text-white rounded-3xl font-black uppercase shadow-xl hover:bg-blue-700 transition-all tracking-widest">{t.save}</button>
            </div>
          ) : (
            <div className="flex-1 overflow-y-auto p-8 space-y-8">
              {stops.length === 0 && <div className="h-full flex flex-col items-center justify-center opacity-20 mt-20 font-black tracking-widest uppercase gap-4 text-slate-400"><MapPin size={48}/><p>{t.empty}</p></div>}
              {Object.entries(groupedStops).map(([phase, data]) => (
                <div key={phase} className="space-y-4 animate-in fade-in duration-500">
                  <div className="px-4 py-1.5 rounded-full inline-block font-black text-[10px] uppercase tracking-widest border" style={{ backgroundColor: `${data.color}15`, color: data.color }}>PHASE {phase}</div>
                  <div className="space-y-3">
                    {data.stops.map((s) => (
                        <div key={s.id} className="p-5 bg-white rounded-3xl border flex items-center justify-between group hover:shadow-xl transition-all cursor-pointer" onClick={()=>{setIsEditing(true); setEditingId(s.id); setNewStop(s);}}>
                          <div className="flex items-center gap-4 truncate">
                            <div className="w-6 h-6 rounded-full flex items-center justify-center text-[10px] font-black text-white" style={{ backgroundColor: s.color }}>{s.phaseIndex}</div>
                            <div className="truncate"><p className="font-black text-slate-700 text-sm uppercase tracking-tight">{s.name}</p><p className="text-[10px] text-slate-400 font-bold">{s.venue} · {s.startDate}</p></div>
                          </div>
                          <div className="flex items-center gap-1 opacity-0 group-hover:opacity-100 transition-all">
                            <button onClick={(e)=>{e.stopPropagation(); moveStop(stops.findIndex(st => st.id === s.id), -1);}} className="p-1 hover:bg-slate-100 rounded text-slate-400"><ChevronUp size={14}/></button>
                            <button onClick={(e)=>{e.stopPropagation(); moveStop(stops.findIndex(st => st.id === s.id), 1);}} className="p-1 hover:bg-slate-100 rounded text-slate-400"><ChevronDown size={14}/></button>
                            <button onClick={(e)=>{e.stopPropagation(); if(window.confirm('Delete Stop?')) remove(ref(db,`projects/${currentProject}/stops/${s.id}`));}} className="p-1 text-red-400 hover:bg-red-50 rounded ml-2 transition-colors"><Trash2 size={14}/></button>
                          </div>
                        </div>
                    ))}
                  </div>
                </div>
              ))}
            </div>
          )}
        </div>
        <div ref={mapContainerRef} className="flex-1 bg-white rounded-[56px] shadow-2xl overflow-hidden relative border-[12px] border-white z-0">
          <div className="h-full w-full" />
        </div>
      </main>
    </div>
  );
}

export default App;